import{_ as t,o as a,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"Meta/Facebook MAI Support","description":"","frontmatter":{"title":"Meta/Facebook MAI Support","slug":"facebook-mai-support"},"headers":[],"relativePath":"account-hub/facebook-mai-support.md","filePath":"account-hub/facebook-mai-support.md"}'),n={name:"account-hub/facebook-mai-support.md"};function s(i,e,p,c,l,d){return a(),o("div",null,[...e[0]||(e[0]=[r('<p>Branch now supports Ads customers who are leveraging Meta&#39;s AEM solution for <strong>Mobile App Install</strong> in conjunction with the previously released Mobile App Engagement 🙌</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>As a reminder, we&#39;re making it easier than before for our valued customers to expand their reach and enhance their ad measurement experience for iOS 14.5+ app campaigns, now for user acquisition objectives. <a href="https://www.facebook.com/business/help/721422165168355?id=1877298665783613" target="_blank" rel="noreferrer">Aggregated Event Measurement (AEM)</a> is Meta&#39;s solution to help advertisers reach more people and measure ad performance on their iOS 14.5+ App Campaigns.</p><p>While there are many different campaign targets the overarching objectives are as follows:</p><table tabindex="0"><thead><tr><th>Campaign Type</th><th>Description</th></tr></thead><tbody><tr><td>Mobile App Engagement</td><td>Aggregate Event Measurement is currently available for the following types of campaigns when the destination is set to a mobile app: sales campaigns with catalog turned on or off, lead campaigns, and engagement campaigns.</td></tr><tr><td>Mobile App Install</td><td>Aggregated Event Measurement has expanded to include campaigns that use the app promotion objective. This means you can now run app promotion campaigns without configuring app events for Apple&#39;s SKAdNetwork, and more app events will be available for ad delivery optimization. You can continue to configure events for SKAdNetwork if you want to view performance across platforms.</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Re-toggling</p><p>You may need to re-toggle the <strong>Enabled Aggregated Event Measurement (AEM)</strong> toggle in the Branch Dashboard if the MAI supported SDK version is updated or if AEM was enabled before MAI rediness release.</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Ready to start measuring AEM Campaigns through Branch? View our guide here: <a href="./enable-app-aggregated-event-measurement-support.html">Enable App Aggregated Event Measurement Support</a></p></div>',7)])])}const m=t(n,[["render",s]]);export{g as __pageData,m as default};
